import{_ as a,o as e,c as n,j as r,a as i,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const A=JSON.parse('{"title":"对城宝具","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/对城宝具.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/对城宝具.md"}'),u={name:"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/对城宝具.md"};function t(p,b,s,l,c,d){return e(),n("div",null,[...b[0]||(b[0]=[r("h1",{id:"对城宝具",tabindex:"-1"},[i("对城宝具 "),r("a",{class:"header-anchor",href:"#对城宝具","aria-label":'Permalink to "对城宝具"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),o('<h1 id="对城宝具-1" tabindex="-1">对城宝具 <a class="header-anchor" href="#对城宝具-1" aria-label="Permalink to &quot;对城宝具&quot;">​</a></h1><p>FATE能力组（对城宝具）<br> 描述：出自型月系列世界观，本能力组为该世界观内从者具有的相关宝具，在购买后主神会将其赋予给轮回者，使轮回者获得具现化对应宝具的能力。<br> 值得一提的是，虽然不同的宝具会被冠以对军、对城、对界等等，但受限于魔力与灵基之流的输出限制，实则并不能真正意义上的一次性摧毁军队、城市等内容。<br> ——<br> 若无特殊说明，则下述宝具消耗的能量为任意通用能量。<br> ——<br> 对城宝具：甚至将城这种牢固的构造物都轰飞的强大宝具，对人宝具与对军宝具的不同是效果范围的不同，可是一旦到对城宝具，威力就变得差距悬殊了。值得一提的是，第四、五次圣杯战争只有 Saber 的“誓约胜利之剑（Excalibur）”是A++等级。</p><p>流光倾泻的命运之枪（Longinus Countzero）（C+～A+）<br> 价格：B+3000<br> 咏唱：移动/标准/整轮<br> 范围：见下<br> 目标：见下<br> 消耗：3/6/9<br> 描述：刺穿了救世主的胸膛的另一把圣枪。<br> 真名解放后的朗基努斯，虽然是可怕的破坏宝具，但同时也具有着治愈的力量。圣枪受到来自加拉哈德与巴林的双重拘束。<br> 这应该可以看作是，骑士王所持的圣枪伦戈米尼亚德（或是异世界的骑士王所持的圣剑Excalibur）中的「十三拘束」的缩小规模吧。主神提供的版本只有解放部分拘束的威能。<br> 效果：<br> 使用前，处理以下三项条件，根据满足条件数量分别可以消耗迅捷（1）/标准（2）/整轮（3）动作进行咏唱，消耗的魔力也依次为3/6/9点，产生不同的效果。若不满足最少一者条件，则即使连最低限度的威力都无法展开。<br> 【须为生存。】<br> 【须与邪恶作战。】<br> 【不得为个人私欲。】<br> ——<br> 【迅捷动作】：满足一项条件可以使用，消耗迅捷动作，解放【流光倾泻的命运之枪（Longinus Countzero）（C+）】。<br> 这将使触及范围内的任一单位（可以是自身）获得持续一轮的快速医疗4，医疗点数48点，同时只能有一个单位享受这一快速医疗带来的效果。<br> ——<br> 【标准动作】：满足两项条件可以使用，消费标准动作，将次轮的第一次攻击变更为【流光倾泻的命运之枪（Longinus Countzero）（B+）】。<br> 本次攻击对前方扇形范围内的敌方单位造成伤害，范围等同于15+自身【传奇决心*10】米，本次攻击检定将获得等同自身【决心】数值的【破魔】。<br> 若计算目标防御后，该能力提供的【破魔】后仍有剩余，则将该能力提供的剩余破魔转为攻击检定上增强加值。<br> ——<br> 【整轮动作】：满足三项条件可以使用，消费标准动作，将次轮的第一次攻击变更为【流光倾泻的命运之枪（Longinus Countzero）（A+）】 。<br> 本次攻击对以自身为中心圆形范围内的敌方单位造成伤害，范围等同于15+自身【传奇决心*10】米，本次攻击检定将获得等同自身决心一半数值的额外附加成功。若对本次攻击出目不满意，则可以进行一次重骰，但必须接受第二次结果。</p><p>五行山·释迦如来掌（Gogyousan Shakanyoraishou）（B）<br> 价格：B+2000<br> 咏唱：整轮动作<br> 范围：20+【传奇风度*10】米<br> 目标：敌对目标<br> 消耗：10<br> 持续：见下<br> 描述：将既是值得尊敬的佛，也是位于天界的（前世）老师，释迦如来之力借用一部分。<br> 孙悟空过去曾经到达过的【世界之端】——亦即释巨大的释迦之掌本身从天而降，惩罚贬低佛法的敌对者。对城宝具。觉者掌底。<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【五行山·释迦如来掌（Gogyousan Shakanyoraishou)】。<br> 这是一次正常的招式攻击，正常进行攻击检定，本次攻击将对范围内的所有敌对目标造成伤害。目标被命中后，必须再进行一次反射豁免对抗伤害出目，失败则陷入B级创伤来源的【定身】效果，该效果将持续一场景。</p><p>白鹭城百鬼八天堂大人（Hakurojyou no Hyakkihachitendousama）<br> 价格：B+3000<br> 咏唱：整轮动作<br> 范围：传奇风度*10米<br> 目标：友方单位（包括自身）<br> 持续：一场景<br> 消耗：10<br> 描述：显现出姬路城的袖珍模型，也就是与所谓的固有结界似是而非的大魔术。凭借数以万人承认的美丽与威严，为己方付与精神上的支柱。<br> 如果攻击性再稍微强一点的话，城会当即化为可以发动攻击的暴力性存在吧，但多亏了原持有者是个天生的家里蹲，才会仅止于防御型宝具。<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【白鹭城百鬼八天堂大人（Hakurojyou no Hyakkihachitendousama)】。<br> 持续时间内，范围内的所有友方单位（包括自身）获得等同风度一半的全伤害吸收效果，以及在防御上获得等同于这个数值的偏斜防御。</p><p>王之号炮（Melammu Dingir）（B）<br> 价格：B+3000<br> 咏唱：整轮动作<br> 范围：武器射程<br> 目标：敌对目标<br> 消耗：10<br> 描述：从乌鲁克要塞发动的远距离轰炸。不只原宝具的持有者，而是集结全体生活于神代的乌鲁克民众的力量发动的令人震惊的炮击。<br> 原本的持有者怀着断肠之痛，将自己的收集品装填于弩上，并交由士兵操作。<br> “幻想崩坏？那种事情，本王4000多年前就干过了！”<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【王之号炮（Melammu Dingir）】。<br> 这是一次正常的招式攻击，正常进行攻击检定，本次攻击将对面前扇形范围内的所有敌对单位造成范围攻击，附带等同自身传奇智力*2点的破甲，高速，破魔，威猛，同时具有的加骰提升1级（上限8加骰），与【超级贯穿】特性<br> 此外，在计算目标防御后，因该能力获得的四种破防效果若仍有剩余，则转换为攻击检定上等量的增强加值。</p><p>六韬三略·魔王尊大羽扇（Rikutousanryaku Maousondaiusen）（A）<br> 价格：B+2500<br> 咏唱：整轮动作<br> 范围：15+【传奇风度*10】米<br> 目标：敌对目标<br> 消耗：10<br> 持续：见下<br> 描述：羽扇指的是用鹰或鹫等羽毛制作的扇子。是指挥部队时使用的道具，但另一方面，也会作为仙人或天狗使用的神秘宝具——隐藏着庞大神通力的道具出现在传说或是图画中。<br> 也就是“天狗的团扇”用作宝具的，就是这把羽扇（羽团扇），可以用破坏力极大这一言以蔽之，伴随着真名解放释放出的风已经到达了风暴、山摇地动天崩地裂的领域了。<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【六韬三略·魔王尊大羽扇（Rikutousanryaku Maousondaiusen）】。<br> 这是一次正常的招式攻击，正常进行攻击检定，本次攻击将对以自身为中心范围内的所有敌对单位进行攻击，同时获得3个额外的附加成功数，伤害改为音波能量伤害。<br> 次轮开始时，该场景天气立刻变更为【十二级飓风】，除自身以外所有单位皆需要承受这一效果带来的负面影响，这是一个B级环境来源带来的影响，无法满足其他效果中所需要的条件。</p><p>神剑·草那艺之大刀（Shinken Kusanaginotachi）（A+）<br> 价格：B+2000<br> 咏唱：整轮动作<br> 范围：15+【传奇力量*10】米<br> 目标：敌对目标<br> 消耗：10<br> 描述：这柄剑的名字就是草那艺之大刀。别名为草薙剑、天丛云剑、都牟刈之太刀。<br> 据说之后被供奉在热田深宫内，被定为三种神器之一。<br> 真名解放的一斩，甚至可怕到能劈开八条山谷与八座山峰，创造出八条大河……但是，这只是暂时借用神剑的些许光辉而已。其真正价值可不止于此。<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【神剑·草那艺之大刀（Shinken Kusanaginotachi））】。<br> 这是一次正常的招式攻击，正常进行攻击检定，本次攻击获得等同自身【力量】*1点增强加值，具有【接触攻击】特性，加骰提升1级计算（上限8加骰），伤害类型转为力场伤害。</p><p>光辉之大复合神殿(Ramesseum Tentyris)（EX）<br> 价格：A+4000<br> 咏唱：整轮动作<br> 范围：敏感范围<br> 目标：敌对目标<br> 消耗：12<br> 描述：将法老—奥兹曼迪亚斯的威光以宝具的形式具现而成之物。 其为组合了众多的巨大神殿及神庙的巨大异形复合神殿体，固有结界的一种。 主要攻击手段虽为藉『丹德拉大电球』进行的魔力炮击，在FGO中施行的则是其杀手锏——大质量攻击（坟头对撞）。<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【光辉之大复合神殿(Ramesseum Tentyris)】。<br> 这是正常的招式攻击，正常进行攻击检定，将对自身为中心范围内的所有敌对单位造成范围攻击。<br> 由于坟头撞击的画面过于震撼，攻击具有A级措手不及效果的影响，依次结算两次攻击，被命中的单位需要使用意志豁免对抗伤害出目，失败则陷入【震慑】状态，持续一轮。</p><p>如同灾祸的太阳之剑（Lvateinn）（A）<br> 价格：A+4500<br> 咏唱：整轮动作<br> 范围：敏感范围<br> 目标：敌对目标<br> 消耗：14<br> 描述：莱瓦汀（Lvateinn）。<br> 据说是苏鲁特武具的炎之剑、弗雷神拥有的太阳剑，以及北欧神洛基所打造的武具三者习合而成的存在。Lvateinn则是由苏鲁特的妻子辛玛拉所保管的传说之剑，据说还施有九重的封印。<br> 既是巨人的武具，亦是神的武具，更还是破灭的先导本身。<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【如同灾祸的太阳之剑（Lvateinn））】。<br> 这是一次正常的招式攻击，正常进行攻击检定，本次攻击将对面前扇形范围内的所有敌对单位造成范围攻击，具有【幻灭】特性，加骰提升1级（最多8加骰），被这个招式击杀的目标如同承受了S级禁止复活效果一样处理。<br> 被命中的单位还需要使用意志豁免对抗伤害出目，失败则立刻死亡，这是一个A命运来源的即死效果。</p><p>闪耀于终焉之枪（Rhongomyniad）（A++）<br> 价格：A+4000<br> 咏唱：整轮动作<br> 范围：敏感范围<br> 目标：敌对目标<br> 消耗：12<br> 描述：圣枪。系住星辰的岚之锚。其真实姿态据说是系住世界表皮的塔。在真名解放时等级和种类会发生变化。纵使被十三拘束限制了其本来的力量，也将歌颂星辰之光而闪烁的至远之枪———<br> 圣枪伦戈米尼亚德将维系世界表层的「光之柱」为本体。由于和「拯救世界的星之圣剑」具有同等程序的十三拘束存在，处于勉强维持作为宝具身形的状态。<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【闪耀于终焉之枪（Rhongomyniad）】。<br> 这是一次正常的招式攻击，正常进行攻击检定，本次攻击获得等同自身【风度】一半的额外附加成功数。<br> 本次攻击将对面前扇形范围内的所有敌对单位造成范围攻击，具有【湮灭】【8加骰】【能量武器】特性，目标使用反射豁免伤害而非正常防御流程。</p><p>契约胜利之剑（Excalibur）（A++）<br> 价格：A+4500<br> 咏唱：整轮动作<br> 范围：敏感范围<br> 目标：敌对目标<br> 消耗：14<br> 描述：这并非人造的武器，而是由星球锻造而成的神造兵器。立于圣剑顶点的宝具。拥有真正强大力量的应是剑鞘，而不是剑本身，但剑鞘据说已永远遗失了。<br> 藉由将所有者的魔力变换成光，再从往下挥的剑的前端如光束一般地放出来破坏万物。在第四次圣杯战争中，曾经一击烧尽由Caster所召唤的身为大海魔的怪物。因其规模与破坏力而被分类为“对城宝具”。<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【契约胜利之剑（Excalibur）】。<br> 这是一次正常的招式攻击，正常进行攻击检定，本次攻击中的武器伤害提升等同自身【风度】*1.5点的数值，小数点无条件忽略。<br> 本次攻击将对面前扇形范围内的所有敌对单位造成范围攻击，具有【幻灭】【余波】，加骰提升1级（最高8加骰），目标使用反射豁免伤害而非正常防御流程，最终造成的伤害将改为光能能量伤害。<br> 如果你对最终出目不满意，则可以进行一次重骰，但必须选择第二次结果。<br> ——<br> 关联亚种：你可以在购买时选择以下几种亚种来取代胜利契约之剑的画风。</p><p>誓约胜利之剑（Excalibur Morgan）A++：黑色极光之剑。由于她不对自己的魔力加以抑制，全力挥动圣剑，令魔力粒子不再是光，而是成为了吞噬光的黑暗。这模样与为了保护不列颠岛而出现的魔龙——伏提庚的气息很相似。因为Excalibur是将所有者的魔力进行变换的增幅器，黑化的Saber的圣剑之光也同样变成了黑色。<br> 尽管不只颜色外观也多少有所差异，但再怎么说也同为Excalibur的另一个侧面。由于湖之妖精薇薇安与摩根并存的原因，这把圣剑也持有善恶两方的属性。</p><p>（圣诞Alter）黑色极光之剑。根本没变。从名字压根就没做任何变更这一方面，能看出来和万圣节的那位从者的差距。对圣诞老人而言是根本用不到的东西，但万一圣诞节恐怕也是要出现些什么怪物，带着总没坏处。</p><p>阳光璀璨胜利之剑（Excalibur Vivian）A：明明都说自己是Archer职阶了，结果还是用这套。真是幼稚。「但原本誓约胜利之剑就是湖之妖精托付给我的东西，就算有水属性也没什么好奇怪的吧？」对此，小阿也只能苦笑。</p><p>选定之拖把。那是在奇妙之园的妖精国度中被奇妙地传唱至今的童话故事。<br> 其柄比阿隆戴特还要坚硬，其顶端比卡文汀还要炙热，其光辉甚至能媲美誓约胜利之剑。能拔出这把拖把的侍从，将会成为某种王吧。</p><p>不挠燃烧胜利之剑（Sequence Morgan）A：亚瑟王拥有的『只会带去死斗场面』的一把名为“Sequence”短剑，乃塞克安斯与誓约胜利之剑的合体宝具。尽管塞克安斯变成了小型自动手枪的样子，但通过与誓约胜利之剑组合，可化为大型狙击枪，在污秽的外敌入侵『主人的领地』前，击退敌人。虽说怎么看都是反器材步枪，但如若不希望自己漂亮的脸蛋遭重击，就千万不要提及这件事。</p><p>无铭胜利剑（Himitsu Calibur）A+：用神秘魔剑『无铭胜利剑』把敌人都杀掉吧。以对Saber发挥绝大威力为傲的圣剑。不能发出光线而是缠绕着光线。此外不知为何挥动的时候会响起砰砰的感觉的重低音。……呐，那个好像在哪听过的样子。</p><p>银河流星剑X（EX）：赐予能够摧毁行星的Saber的力量。又名为“绝对能杀死Saber的剑”。因为是对Saber的特攻，有了这个的话就算说自己是Saber中的Saber也不算言过其实吧？重获新生的第二宝具，只要对手是物理上的就没有斩不断的东西。是只有谜之女主角X才能使用的高于EX等级之上的技能。</p><p>黑龙双克胜利剑（Cross Calibur）A++：引以为傲的剑『邪圣剑死之胜利剑』是通过可疑的邮购买来的。释放出赤色魔力的“邪圣剑死之胜利剑”能够自如变化成双剑或是电锯之类的样子，但经常会坏或是发生爆炸。越是帅气的武器越是不强，这似乎是宇宙共通的规则。还是平淡无奇的长剑最棒了。</p><p>煌彩幻奏霸道剑（Lumino Calibur）B：据说只有与音乐之魔结下契约的人才能弹奏出的，禁断的吉他剑“邪圣弦 Lumino Calibur”（在行星茶水的宝具大甩卖期间以超低价购入的）。<br> 炼成的超EMO离子·偶像元素，可以将场地变为光线摇摆的舞台。<br> 月虹大河即光亮。幽冥神籁亦调和。倾听吾剑之歌声——煌彩幻奏霸道剑！</p><p>必胜黄金之剑（Caliburn）B：本来是用于选拔王者之剑。对人宝具中的『对人』不是对敌人，而是针对将要持剑之主。当其持有者成为一名贯彻正确之举或是完美的王时，其威力将不愧对于圣剑之名。<br> Caliburn与Excalibur是不同的圣剑。Caliburn也就是王权，为了将亚瑟王培养成一名王的存在。Caliburn原本是仪式用剑。若将其用作武器，一旦解放真名，甚至能发挥与Excalibur同规模的威力，然而其剑身并不能承受阿尔托莉雅的魔力，想必会崩溃吧。</p><p>永久遥远黄金之剑（Excalibur Image）：与誓约胜利之剑（Excalibur）接近的仿制品。那是在遥远的过去，只剩下些许记忆的少年时代里，永远烙印在心中的那位王所持有的黄金之剑。</p><p>永久遥远胜利之剑（Excalibur）A+：因理查极度崇拜亚瑟王，甚至将拿到手的东西都当成Excalibur的传说升华而成的宝具。<br> 只要是理查拿在手中的东西，兵器也好餐具也罢，甚至是路边捡来的树枝都能当成Excalibur放出光之斩击进行远程攻击。其所使用的佩剑只是普通的仿制品，这一能力本身才是真正的宝具。威力理所当然地比不上真正的Excalibur，但仍相当具有威胁性。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',26)])])}const m=a(u,[["render",t]]);export{A as __pageData,m as default};
